      "src/app/features/task-manager/components/add-task-form/add-task-form.component.scss": "\n.add-task-form {\n  display: flex;\n  gap: 8px;\n  margin-bottom: 24px;\n\n  input {\n    flex-grow: 1;\n    padding: 12px;\n    border: 1px solid #ccc;\n    border-radius: 4px;\n    font-size: 16px;\n\n    &:focus {\n      outline: none;\n      border-color: #007bff;\n      box-shadow: 0 0 0 2px rgba(0, 123, 255, 0.25);\n    }\n  }\n\n  button {\n    padding: 12px 20px;\n    font-size: 16px;\n    color: #fff;\n    background-color: #007bff;\n    border: none;\n    border-radius: 4px;\n    cursor: pointer;\n    transition: background-color 0.2s;\n\n    &:hover {\n      background-color: #0056b3;\n    }\n\n    &:disabled {\n      background-color: #a0c7e4;\n      cursor: not-allowed;\n    }\n  }\n}\n",
      "src/app/features/task-manager/task-manager.component.ts": "\nimport { Component, OnInit, inject } from '@angular/core';\nimport { CommonModule } from '@angular/common';\nimport { Observable, BehaviorSubject, switchMap, catchError, of, tap } from 'rxjs';\nimport { Task } from '../../core/models/task.model';\nimport { TaskService } from '../../core/services/task.service';\nimport { AddTaskFormComponent } from './components/add-task-form/add-task-form.component';\nimport { TaskListComponent } from './components/task-list/task-list.component';\n\n@Component({\n  selector: 'app-task-manager',\n  standalone: true,\n  imports: [CommonModule, AddTaskFormComponent, TaskListComponent],\n  templateUrl: './task-manager.component.html',\n  styleUrls: ['./task-manager.component.scss']\n})\nexport class TaskManagerComponent implements OnInit {\n  private taskService = inject(TaskService);\n\n  tasks$!: Observable<Task[]>;\n  error: string | null = null;\n  loading = true;\n\n  private refreshTasks$ = new BehaviorSubject<void>(undefined);\n\n  ngOnInit() {\n    this.tasks$ = this.refreshTasks$.pipe(\n      tap(() => {\n        this.loading = true;\n        this.error = null;\n      }),\n      switchMap(() => this.taskService.getTasks()),\n      tap(() => this.loading = false),\n      catchError(err => {\n        this.error = 'Failed to load tasks.';\n        this.loading = false;\n        console.error(err);\n        return of([]);\n      })\n    );\n  }\n\n  handleAddTask(title: string) {\n    this.taskService.addTask(title).pipe(\n      catchError(err => {\n        this.error = 'Failed to add task.';\n        console.error(err);\n        return of(null);\n      })\n    ).subscribe(task => {\n      if (task) {\n        this.refreshTasks$.next();\n      }\n    });\n  }\n\n  handleCompleteTask(taskId: number) {\n    this.taskService.deleteTask(taskId).pipe(\n      catchError(err => {\n        this.error = 'Failed to complete task.';\n        console.error(err);\n        return of(null);\n      })\n    ).subscribe(result => {\n      // On successful deletion from service (which updates the signal), refresh the view\n      if (result === undefined) {\n         this.refreshTasks$.next();\n      }\n    });\n  }\n}\n",
      "src/app/core/services/task.service.ts": "\nimport { Injectable, signal } from '@angular/core';\nimport { of, Observable, throwError, delay } from 'rxjs';\nimport { Task } from '../models/task.model';\n\n@Injectable({\n  providedIn: 'root'\n})\nexport class TaskService {\n  private tasks = signal<Task[]>([]);\n  private initialTasks: Task[] = [\n    {\n      taskId: 1,\n      title: 'Finish the project report',\n      status: 'pending',\n      createdAt: '2023-10-27T10:00:00Z',\n      updatedAt: '2023-10-27T10:00:00Z'\n    },\n    {\n      taskId: 2,\n      title: 'Buy groceries',\n      status: 'pending',\n      createdAt: '2023-10-27T10:05:00Z',\n      updatedAt: '2023-10-27T10:05:00Z'\n    },\n    {\n      taskId: 3,\n      title: 'Schedule a dentist appointment',\n      status: 'pending',\n      createdAt: '2023-10-28T11:00:00Z',\n      updatedAt: '2023-10-28T11:00:00Z'\n    }\n  ];\n\n  constructor() {\n    this.tasks.set(this.initialTasks);\n  }\n\n  getTasks(): Observable<Task[]> {\n    // Mocking an API call with a delay\n    return of(this.tasks()).pipe(delay(500));\n  }\n\n  addTask(title: string): Observable<Task> {\n    if (!title.trim()) {\n      return throwError(() => new Error('Task title cannot be empty.'));\n    }\n\n    const newTask: Task = {\n      taskId: Math.floor(Math.random() * 1000) + 1, // Mocking ID generation\n      title: title,\n      status: 'pending',\n      createdAt: new Date().toISOString(),\n      updatedAt: new Date().toISOString()\n    };\n\n    this.tasks.update(tasks => [...tasks, newTask]);\n\n    // Mocking an API call with a delay\n    return of(newTask).pipe(delay(300));\n  }\n\n  deleteTask(taskId: number): Observable<void> {\n    const taskExists = this.tasks().some(task => task.taskId === taskId);\n    if (!taskExists) {\n      return throwError(() => new Error(`Task with id ${taskId} not found.`));\n    }\n\n    this.tasks.update(tasks => tasks.filter(task => task.taskId !== taskId));\n\n    // Mocking an API call with a delay\n    return of(undefined).pipe(delay(300));\n  }\n}\n",
      "src/app/features/task-manager/components/task-item/task-item.component.scss": "\n.task-item {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  padding: 16px;\n  background-color: #fff;\n  border: 1px solid #e0e0e0;\n  border-radius: 4px;\n  transition: box-shadow 0.2s;\n\n  &:not(:last-child) {\n    margin-bottom: 12px;\n  }\n\n  &:hover {\n    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);\n  }\n}\n\n.task-title {\n  font-size: 16px;\n  color: #333;\n}\n\n.complete-btn {\n  padding: 8px 16px;\n  font-size: 14px;\n  color: #fff;\n  background-color: #28a745;\n  border: none;\n  border-radius: 4px;\n  cursor: pointer;\n  transition: background-color 0.2s;\n\n  &:hover {\n    background-color: #218838;\n  }\n}\n",
