      "src/app/features/task-manager/components/task-item/task-item.component.ts": "\nimport { Component, Input, Output, EventEmitter } from '@angular/core';\nimport { CommonModule } from '@angular/common';\nimport { Task } from '../../../../core/models/task.model';\n\n@Component({\n  selector: 'app-task-item',\n  standalone: true,\n  imports: [CommonModule],\n  templateUrl: './task-item.component.html',\n  styleUrls: ['./task-item.component.scss']\n})\nexport class TaskItemComponent {\n  @Input({ required: true }) task!: Task;\n  @Output() complete = new EventEmitter<number>();\n\n  onComplete() {\n    this.complete.emit(this.task.taskId);\n  }\n}\n",
      "src/app/features/task-manager/components/task-list/task-list.component.html": "\n<div class=\"task-list-container\">\n  <div *ngIf=\"!tasks || tasks.length === 0; else taskItems\" class=\"empty-state\">\n    <p>No tasks yet. Add one above!</p>\n  </div>\n\n  <ng-template #taskItems>\n    <app-task-item\n      *ngFor=\"let task of tasks;\"\n      [task]=\"task\"\n      (complete)=\"onCompleteTask($event)\">\n    </app-task-item>\n  </ng-template>\n</div>\n",
      "src/app/features/task-manager/components/add-task-form/add-task-form.component.ts": "\nimport { Component, EventEmitter, Output, inject } from '@angular/core';\nimport { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';\nimport { CommonModule } from '@angular/common';\n\n@Component({\n  selector: 'app-add-task-form',\n  standalone: true,\n  imports: [CommonModule, ReactiveFormsModule],\n  templateUrl: './add-task-form.component.html',\n  styleUrls: ['./add-task-form.component.scss']\n})\nexport class AddTaskFormComponent {\n  @Output() addTask = new EventEmitter<string>();\n  private fb = inject(FormBuilder);\n\n  taskForm = this.fb.group({\n    title: ['', Validators.required]\n  });\n\n  onSubmit() {\n    if (this.taskForm.valid && this.taskForm.value.title) {\n      this.addTask.emit(this.taskForm.value.title);\n      this.taskForm.reset();\n    }\n  }\n}\n",
      "src/app/app.component.ts": "\nimport { Component } from '@angular/core';\nimport { CommonModule } from '@angular/common';\nimport { TaskManagerComponent } from './features/task-manager/task-manager.component';\n\n@Component({\n  selector: 'app-root',\n  standalone: true,\n  imports: [CommonModule, TaskManagerComponent],\n  template: '<app-task-manager></app-task-manager>',\n  styles: []\n})\nexport class AppComponent {\n  title = 'todo-frontend';\n}\n",
