      "src/app/features/task-manager/task-manager.component.html": "\n<div class=\"task-manager\">\n  <header>\n    <h1>My Tasks</h1>\n  </header>\n\n  <app-add-task-form (addTask)=\"handleAddTask($event)\"></app-add-task-form>\n\n  <div *ngIf=\"loading\" class=\"loading-indicator\">Loading tasks...</div>\n\n  <div *ngIf=\"error\" class=\"error-message\">{{ error }}</div>\n\n  <div *ngIf=\"!loading && !error\">\n    <app-task-list [tasks]=\"tasks$ | async\" (completeTask)=\"handleCompleteTask($event)\"></app-task-list>\n  </div>\n</div>\n",
